export async function GET(req: Request) {
  const url = new URL(req.url)
  if (url.searchParams.get('secret') !== 'turbo-seed-2026') return NextResponse.json({ error: 'unauthorized' }, { status: 401 })
  const supabase = createClient(process.env.NEXT_PUBLIC_SUPABASE_URL!, process.env.SUPABASE_SERVICE_ROLE_KEY!)
  const res: any[] = []
  for (const P of POSTS) {
    const buffer = Buffer.from(IMAGES[P.key], 'base64')
    const path = `${P.slug}.jpg`
    await supabase.storage.from('blog').upload(path, buffer, { contentType: 'image/jpeg', upsert: true })
    const coverUrl = supabase.storage.from('blog').getPublicUrl(path).data.publicUrl
    await supabase.from('blog_posts').delete().eq('slug', P.slug)
    const { error } = await supabase.from('blog_posts').insert({
      title: P.title, slug: P.slug, excerpt: P.excerpt, content: P.content,
      category: P.category, author: 'Equipe Cardápio Turbo', cover_emoji: P.emoji, cover_image: coverUrl,
      read_minutes: 7, seo_title: P.seo_title, seo_description: P.seo_desc, keywords: P.keywords,
      published: true, published_at: new Date().toISOString(), updated_at: new Date().toISOString(),
    })
    res.push({ slug: P.slug, error: error?.message ?? null })
  }
  return NextResponse.json({ ok: true, res })
}
